  Q['black_ideology_base' + character] = characterFreedom/2;
  Q['latino_ideology_base' + character] = characterFreedom/4;
  Q['business_ideology_base' + character] = characterOrder;

  // remember to add in a cap to black and latino minorities later.

  // Calculate the total pool for distribution in the approval rating.

  Q['ideology_support_' + character] = 0;

    for (var c of Q.classes) {
        if ([Q[c + '_ideology_base_' + character]] == 0) {
          Q[c + '_ideology_base_' + character] = 1;
        }
        if (Q[c + '_ideology_base_' + character] > 0) {
          Q['ideology_support_' + character] += (Q[c + '_ideology_base_' + character]);
        } else if ([Q[c + '_ideology_base']] < 0) {
          Q['ideology_support_' + character] += (Q[c + '_ideology_base_' + character])*(-1);
        }
  }

  // Now we'll divide the ideology share to find the "pull".

  Q['unemployed_ideology_' + character] = (Q['unemployed_ideology_base_' + character]/Q['ideology_support_' + character]);
  Q['blue_collar_ideology_' + character] = (Q['blue_collar_ideology_base_' + character]/Q['ideology_support_' + character]);
