function demographicApprovalRating () {

// We now will scale the support by the character's approval rating.
// We do so first by checking every demographic support and seeing if it's under the approval rating.
// If it's under the approval rating, it adds to an approval gap. If it's above, it will remove the approval gap. The approval gap later on gets spread across different demographics, scaled by order vs freedom weights, so that the support of the demographics will always be your approval rating.
// First, we need to determine the ideological weights for this. Some of the values are negative, so we have to turn them positive.

if(Q['approval_rating_' + character]) {
    for (var c of Q.classes) {
      if (Q[c + '_ideology_' + character] > 0) {
          Q[c + '_approval_weight_' + character] = Q[c + '_ideology_' + character];
      } else {
          Q[c + '_approval_weight_' + character] = (Q[c + '_ideology_' + character])*(-1);
      }
    }


  Q['approval_gap_' + character] = 0;

    for (var c of Q.classes) {
          Q[c + '_approval_gap_' + character] = ((Q['approval_rating_' + character])-(Q[c + '_support_' + character]));
          Q['approval_gap_' + character] += (Q[c + '_approval_gap_' + character]);
  }


  for (var c of Q.classes) {
        Q[c + '_support_' + character] += ((Q['approval_gap_' + character])*(Q[c + '_approval_weight_' + character]));
    }

}

for (var c of Q.classes) {
       if (Q[c + '_support_' + character] > 100) {
        Q[c + '_support_' + character] = 100
  }
  if (Q[c + '_support_' + character] < 0) {
    Q[c + '_support_' + character] = 0
  }
}

}

// Second last, we need to find districts. Since they are based off preexisting support, we need to put it after the global supports are found out.

function demographicDistrictSupport() {

// We get the per district support values by taking the support and scaling it by size within a district.


  for (var district of Q.districts) {
    for (var c of Q.classes) {
        Q[c + '_' + district + '_support_' + character] = Q[c + '_support_' + character]*(Q[c + '_' + district]/100);
    }
  }

  // We have the sizes now. E.c 8% unemployed in Burnley, with 55% city unemployed support, you get 4.4% of the unemployed supporting you.
  // now we have to convert it back to percentage.
  // First we define each district total (e.c the sum of all support), then take the district support and add them all together to form total support


  for (var district of Q.districts) {
    Q[district + '_total_' + character] = 0;
    for (var c of Q.classes) {
        Q[district + '_total_' + character] += (Q[c + '_' + district + '_support_' + character]);
    }
  }

  // This gives us the support combined (e.c 51% of burnley supports Bruce), but not the individual contributions. Luckily we can now simply scale the support by the district's total to figure how much each demographic contributes.

  for (var district of Q.districts) {
    for (var c of Q.classes) {
        Q[c + '_' + district + '_total_' + character] += ((Q[c + '_' + district + '_support_' + character])/(Q[district + '_total_' + character]))*100;
    }
  }


  for (var district of Q.districts) {
    for (var c of Q.classes) {
        Q[c + '_' + district + '_approval_' + character] = (Q[c + '_' + district + '_support_' + character]/Q[c + '_' + district])*100;
    }
  }

// For short. With c as class and district as the district.
// Using the values of 8% unemployed in burnley and 55% unemployed support as examples.
// c_district_support gives us the population's exact contribution. E.c if there are 8% unemployed in Burnley, and we have 55% support, we get 4.4%. This can then be affected by individual factors.
// c_district_total gives us the individual contribution to the support. E.c if we have 55% support in burnley and the aforementioned values, unemployed/district gives us a 8% contribution. This lets us see our biggest demographics and such.
// c_support is citywide support from a given demographic.
// Lastly, c_district_approval is simply the percentage.

// All things that affect districts should affect c_district_support.

// Figure out spread of party per district


  for (var district of Q.districts) {
    for (var c of Q.classes) {
      for (var party of Q.parties) {
        Q[c + '_' + party + '_' + district + '_support'] = (Q[c + '_' + party])*((Q[c + '_' + district])/100);

