        Q[c + '_' + party + '_' + district + '_number'] = (((Q[c + '_' + party])*((Q[c + '_' + district])/100))/100)*((Q.gotham_population)*(Q[district + '_size']/100));

      }

    }
  }

  // Display numbers of people into format of 100.1k


