      }
    }
  }

}

// must be calculated at ending:
// getting city wide support
// These are conversions into useful values.

function demographicConversion() {

    Q['city_wide_support_' + character] = 0;

    for (var c of Q.classes) {
        Q['city_wide_support_' + character] += (Q[c + '_support_' + character])/6;
    }

  // District to city wide support.

  for (var district of Q.districts) {
    for (var c of Q.classes) {
        Q[c + '_' + district + '_city_total'] = Q[district + '_size']*((Q[c + '_' + district])/100)
    }
  }

  for (var district of Q.districts) {
    for (var c of Q.classes) {
        Q[c + '_' + district + '_city_' + character] = ((Q[c + '_' + district + '_city_total']))*(Q[c + '_' + district + '_approval_' + character]/100)
    }
  }

  // real support city wide. E.c not dividing the universals by six, but the sum of all district contributions.

  Q['truesupport_' + character] = 0;

  for (var district of Q.districts) {
    for (var c of Q.classes) {
        Q['truesupport_' + character] += (Q[c + '_' + district + '_support']);
    }
  }

// The following isn't a division by the classes, but by the number of districts.

  Q['truesupport_' + character] = Q['truesupport_' + character]/6

  // Getting old values.

  for (var c of Q.classes) {
      Q[c +'_support_old_' + character] = Q[c + '_support_' + character];
  }

  for (var c of Q.classes) {
    for (var party of Q.parties) {
      Q[c + '_' + party + '_support_old_' + character] = Q[c + '_' + party + '_support_' + character];
    }
  }

}

